/* ── Right Thread Panel ── */
.thread-panel {
    width: 25%;
    min-width: 260px;
    background: #1e2024;
    border-left: 1px solid #303236;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #303236;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
}

.close-btn {
    background: none;
    border: none;
    color: #b5bac1;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #383a40;
    color: #fff;
}

.thread-root-quote {
    padding: 12px 16px;
    border-bottom: 1px solid #303236;
    background: #27242c;
    flex-shrink: 0;
}

.thread-root-quote .author {
    font-size: 0.85rem;
}

.thread-root-quote p {
    margin: 4px 0 0;
    font-size: 0.9rem;
    color: #b5bac1;
    line-height: 1.4;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px 0;
}

.thread-reply .message-bubble {
