}

/* ── Scrollbar styling ── */
.message-list::-webkit-scrollbar,
.thread-messages::-webkit-scrollbar,
.channel-list::-webkit-scrollbar {
    width: 6px;
}

.message-list::-webkit-scrollbar-track,
.thread-messages::-webkit-scrollbar-track,
.channel-list::-webkit-scrollbar-track {
    background: transparent;
}

.message-list::-webkit-scrollbar-thumb,
.thread-messages::-webkit-scrollbar-thumb,
.channel-list::-webkit-scrollbar-thumb {
    background: #404249;
    border-radius: 3px;
}

namespace sv_148db7aaa67241318e8ae7708b50bb6e.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_148db7aaa67241318e8ae7708b50bb6e.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <main class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <span class="author">@msg.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-content">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reactions-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                    @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)">
                                                @r.Emoji @r.Users.Count
                                            </button>
                                        }
                                    </div>
                                }

                                @{ var replyCount = GetReplyCount(msg.Id); }
                                @if (msg.ReplyToId is null && replyCount > 0)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        @replyCount @(replyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">
                                        😀 React
                                    </button>
                                </div>

                                @if (_emojiPickerMessageId == msg.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in _commonEmojis)
                                        {
                                            <button class="emoji-btn"
                                                    @onclick="() => AddReactionFromPickerAsync(msg.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="msg-input" rows="2" placeholder="Type a message…"
                          @bind="_newMessage" @bind:event="oninput"
                          @onkeydown="OnMessageKeyDown" />
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessage)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* ── Right Thread Panel ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@_threadRootMessage.Author</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-messages" @ref="_threadListRef">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-row thread-reply">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <span class="author">@reply.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                                </div>
                                <div class="message-content">@reply.Content</div>
                                @if (reply.Reactions.Count > 0)
                                {
                                    <div class="reactions-row">
                                        @foreach (var r in reply.Reactions)
                                        {
                                            <button class="reaction-badge"
                                                    title="@string.Join(", ", r.Users)"
                                                    @onclick="() => ToggleReactionAsync(reply.Id, r.Emoji)">
                                                @r.Emoji @r.Users.Count
                                            </button>
                                        }
                                    </div>
                                }
                            </div>
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="msg-input" rows="2" placeholder="Reply in thread…"
                          @bind="_newThreadReply" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_newThreadReply)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    // ── State ──
    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private int _messageSkip;
    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private string _newMessage = "";
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _newThreadReply = "";

    // Reply count lookup built from loaded messages
    private Dictionary<int, int> _replyCounts = new();

    // Element references for scroll management
    private ElementReference _messageListRef;
    private ElementReference _threadListRef;

    // JS module for scroll helpers
    private IJSObjectReference? _jsModule;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-148db7aaa67241318e8ae7708b50bb6e/js/chat-scroll.js"
                ?? "./js/chat-scroll.js");
        }
    }

    // ── Channel selection ──
    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messages = null;
        _messageSkip = 0;
        _allMessagesLoaded = false;
        _replyCounts.Clear();
        CloseThread();

        var msgs = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = msgs;
        _messageSkip = msgs.Count;
        BuildReplyCounts();

        await ChatService.MarkChannelReadAsync(channel.Id);
        UpdateChannelUnread(channel.Id);

        await Task.Yield();
        await ScrollToBottomAsync(_messageListRef);
    }

    // ── Infinite scroll (load older) ──
    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannelId is null || _jsModule is null) return;

        var scrollTop = await _jsModule.InvokeAsync<double>("getScrollTop", _messageListRef);
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var prevHeight = await _jsModule.InvokeAsync<double>("getScrollHeight", _messageListRef);

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messageSkip, PageSize);
        if (older.Count == 0)
        {
            _allMessagesLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            BuildReplyCounts();
        }

        _loadingMore = false;
        StateHasChanged();
        await Task.Yield();

        // Maintain scroll position after prepending
        if (older.Count > 0)
        {
            await _jsModule.InvokeVoidAsync("maintainScrollPosition", _messageListRef, prevHeight);
        }
    }

    // ── Sending messages ──
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _messageSkip++;
        _newMessage = "";

        StateHasChanged();
        await Task.Yield();
        await ScrollToBottomAsync(_messageListRef);
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    // ── Reactions ──
    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionFromPickerAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ToggleReactionAsync(messageId, emoji);
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh the affected message list
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messageSkip);
            BuildReplyCounts();
        }

        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    // ── Thread panel ──
    private async Task OpenThreadAsync(Message rootMsg)
    {
        _threadRootMessage = rootMsg;
        _threadMessages = await ChatService.GetThreadAsync(rootMsg.Id);
        _threadOpen = true;
        _newThreadReply = "";

        StateHasChanged();
        await Task.Yield();
        await ScrollToBottomAsync(_threadListRef);
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _newThreadReply = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_newThreadReply) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newThreadReply.Trim(), _threadRootMessage.Id);
        _threadMessages ??= [];
        _threadMessages.Add(sent);
        _newThreadReply = "";

        // Update the reply count in the main view
        _replyCounts[_threadRootMessage.Id] = _threadMessages.Count(m => m.Id != _threadRootMessage.Id);

        StateHasChanged();
        await Task.Yield();
        await ScrollToBottomAsync(_threadListRef);
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──
    private void BuildReplyCounts()
    {
        if (_messages is null) return;
        _replyCounts.Clear();
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _replyCounts.TryGetValue(rootId, out var count);
            _replyCounts[rootId] = count + 1;
        }
    }

    private int GetReplyCount(int messageId)
    {
        _replyCounts.TryGetValue(messageId, out var count);
        return count;
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 40 ? desc[..37] + "…" : desc;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private async Task ScrollToBottomAsync(ElementReference el)
    {
        if (_jsModule is not null)
        {
            try { await _jsModule.InvokeVoidAsync("scrollToBottom", el); }
            catch (JSDisconnectedException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try { await _jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

