                                    </div>
                                }
                            </div>
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="msg-input" rows="2" placeholder="Reply in thread…"
                          @bind="_newThreadReply" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_newThreadReply)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    // ── State ──
    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private int _messageSkip;
    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private string _newMessage = "";
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _newThreadReply = "";

    // Reply count lookup built from loaded messages
    private Dictionary<int, int> _replyCounts = new();

    // Element references for scroll management
    private ElementReference _messageListRef;
    private ElementReference _threadListRef;

    // JS module for scroll helpers
    private IJSObjectReference? _jsModule;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-148db7aaa67241318e8ae7708b50bb6e/js/chat-scroll.js"
                ?? "./js/chat-scroll.js");
        }
    }

    // ── Channel selection ──
    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messages = null;
        _messageSkip = 0;
        _allMessagesLoaded = false;
        _replyCounts.Clear();
        CloseThread();

        var msgs = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = msgs;
        _messageSkip = msgs.Count;
        BuildReplyCounts();

        await ChatService.MarkChannelReadAsync(channel.Id);
        UpdateChannelUnread(channel.Id);

        await Task.Yield();
        await ScrollToBottomAsync(_messageListRef);
    }

    // ── Infinite scroll (load older) ──
    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannelId is null || _jsModule is null) return;

        var scrollTop = await _jsModule.InvokeAsync<double>("getScrollTop", _messageListRef);
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var prevHeight = await _jsModule.InvokeAsync<double>("getScrollHeight", _messageListRef);

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messageSkip, PageSize);
        if (older.Count == 0)
        {
            _allMessagesLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            BuildReplyCounts();
        }

        _loadingMore = false;
        StateHasChanged();
        await Task.Yield();

        // Maintain scroll position after prepending
        if (older.Count > 0)
        {
            await _jsModule.InvokeVoidAsync("maintainScrollPosition", _messageListRef, prevHeight);
        }
    }

    // ── Sending messages ──
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _messageSkip++;
        _newMessage = "";

        StateHasChanged();
        await Task.Yield();
        await ScrollToBottomAsync(_messageListRef);
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    // ── Reactions ──
    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionFromPickerAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ToggleReactionAsync(messageId, emoji);
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh the affected message list
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messageSkip);
            BuildReplyCounts();
        }

        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    // ── Thread panel ──
    private async Task OpenThreadAsync(Message rootMsg)
    {
        _threadRootMessage = rootMsg;
        _threadMessages = await ChatService.GetThreadAsync(rootMsg.Id);
        _threadOpen = true;
        _newThreadReply = "";

        StateHasChanged();
        await Task.Yield();
        await ScrollToBottomAsync(_threadListRef);
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _newThreadReply = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_newThreadReply) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newThreadReply.Trim(), _threadRootMessage.Id);
        _threadMessages ??= [];
        _threadMessages.Add(sent);
        _newThreadReply = "";

        // Update the reply count in the main view
        _replyCounts[_threadRootMessage.Id] = _threadMessages.Count(m => m.Id != _threadRootMessage.Id);

        StateHasChanged();
        await Task.Yield();
        await ScrollToBottomAsync(_threadListRef);
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──
    private void BuildReplyCounts()
    {
        if (_messages is null) return;
        _replyCounts.Clear();
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _replyCounts.TryGetValue(rootId, out var count);
            _replyCounts[rootId] = count + 1;
        }
    }

    private int GetReplyCount(int messageId)
    {
        _replyCounts.TryGetValue(messageId, out var count);
        return count;
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
