            _replyCounts.TryGetValue(rootId, out var count);
            _replyCounts[rootId] = count + 1;
        }
    }

    private int GetReplyCount(int messageId)
    {
        _replyCounts.TryGetValue(messageId, out var count);
        return count;
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 40 ? desc[..37] + "…" : desc;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
