toolArgs.file_text:
/* ── Layout shell ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: #1a1d21;
    color: #d1d2d3;
}

/* ── Left Sidebar ── */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #19171d;
    border-right: 1px solid #303236;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #303236;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #27242c;
}

.channel-item.active {
    background: #1264a3;
}

.channel-item.active .channel-name,
.channel-item.active .channel-desc {
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #cfc3cf;
}

.channel-desc {
    font-size: 0.75rem;
    color: #9b8e9b;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main Message Area ── */
.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    transition: width 0.2s ease;
}

.message-area.expanded {
    width: 80%;
}

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #303236;
    background: #1a1d21;
    flex-shrink: 0;
}

.message-header h2 {
    margin: 0;
    font-size: 1.15rem;
    color: #fff;
}

.header-desc {
    font-size: 0.8rem;
    color: #9b9d9f;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 20px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #9b9d9f;
    font-size: 0.85rem;
}

.message-row {
    position: relative;
    padding: 6px 0;
}

.message-row:hover {
    background: #222529;
    border-radius: 6px;
}

.message-bubble {
    padding: 4px 8px;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #fff;
}

.timestamp {
    font-size: 0.75rem;
    color: #616061;
}

.message-content {
    font-size: 0.95rem;
    line-height: 1.45;
    color: #d1d2d3;
    white-space: pre-wrap;
    word-break: break-word;
}

/* Reactions */
.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    background: #2b2d31;
    border: 1px solid #404249;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #d1d2d3;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #383a40;
    border-color: #5865f2;
}

/* Thread link */
.thread-link {
    background: none;
    border: none;
    color: #1d9bd1;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

/* Hover action buttons */
.message-actions {
    position: absolute;
    top: -4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #2b2d31;
    border: 1px solid #404249;
    border-radius: 6px;
    padding: 2px;
    z-index: 10;
    box-shadow: 0 2px 8px rgba(0,0,0,.4);
}

.action-btn {
    background: none;
    border: none;
    color: #b5bac1;
    font-size: 0.8rem;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #383a40;
    color: #fff;
}

/* Emoji picker */
.emoji-picker {
    position: absolute;
    top: -4px;
    right: 140px;
    display: flex;
    gap: 2px;
    background: #2b2d31;
    border: 1px solid #404249;
    border-radius: 8px;
    padding: 6px;
    z-index: 11;
    box-shadow: 0 4px 12px rgba(0,0,0,.5);
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.3rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    transition: background 0.15s;
}

.emoji-btn:hover {
    background: #383a40;
}

/* Message input */
.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 8px 20px 12px;
    border-top: 1px solid #303236;
    background: #1a1d21;
    flex-shrink: 0;
}

.msg-input {
    flex: 1;
    resize: none;
    background: #222529;
    border: 1px solid #404249;
    border-radius: 8px;
    color: #d1d2d3;
    padding: 10px 12px;
    font-size: 0.95rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.msg-input:focus {
    border-color: #1d9bd1;
}

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-weight: 700;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #148567;
}

.send-btn:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #616061;
    font-size: 1.1rem;
}

/* ── Right Thread Panel ── */
.thread-panel {
    width: 25%;
    min-width: 260px;
    background: #1e2024;
    border-left: 1px solid #303236;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #303236;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
}

.close-btn {
    background: none;
    border: none;
    color: #b5bac1;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #383a40;
    color: #fff;
}

.thread-root-quote {
    padding: 12px 16px;
    border-bottom: 1px solid #303236;
    background: #27242c;
    flex-shrink: 0;
}

.thread-root-quote .author {
    font-size: 0.85rem;
}

.thread-root-quote p {
    margin: 4px 0 0;
    font-size: 0.9rem;
    color: #b5bac1;
    line-height: 1.4;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px 0;
}

.thread-reply .message-bubble {
    padding: 4px 0;
}

/* ── Scrollbar styling ── */
.message-list::-webkit-scrollbar,
.thread-messages::-webkit-scrollbar,
.channel-list::-webkit-scrollbar {
    width: 6px;
}

.message-list::-webkit-scrollbar-track,
.thread-messages::-webkit-scrollbar-track,
.channel-list::-webkit-scrollbar-track {
    background: transparent;
}

.message-list::-webkit-scrollbar-thumb,
.thread-messages::-webkit-scrollbar-thumb,
.channel-list::-webkit-scrollbar-thumb {
    background: #404249;
    border-radius: 3px;
}

